namespace sv_aacaaa7e97f2413b8061890ed6ee64d6.Services;

public class AppointmentService
{
    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(new List<string>
        {
            "Dr. Smith",
            "Dr. Johnson",
            "Dr. Patel",
            "Dr. Williams"
        });
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date)
    {
        return Task.FromResult(new List<string>
        {
            "9:00 AM",
            "10:00 AM",
            "11:00 AM",
            "1:00 PM",
            "2:00 PM",
            "3:00 PM"
        });
    }

    public Task<Dictionary<string, string>> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var errors = new Dictionary<string, string>();

        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors["Email"] = "Account has outstanding balance";
        }

        if (insuranceProvider == "None" && doctor == "Dr. Smith")
        {
            errors["Doctor"] = "Selected doctor does not accept self-pay patients";
        }

        if (timeSlot == "10:00 AM")
        {
            errors["TimeSlot"] = "This slot is no longer available";
        }

        return Task.FromResult(errors);
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_aacaaa7e97f2413b8061890ed6ee64d6.Services
@inject AppointmentService AppointmentService

<h1>Book Appointment</h1>

<EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="bookAppointment">
    <DataAnnotationsValidator />

    <h3>Step 1: Patient Information</h3>

    <div class="mb-3">
        <label class="form-label">Patient Name</label>
        <InputText class="form-control" @bind-Value="Model.PatientName" />
        <ValidationMessage For="() => Model.PatientName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="Model.Email" />
        <ValidationMessage For="() => Model.Email" />
        @if (serverErrors.ContainsKey("Email"))
        {
            <div class="validation-message">@serverErrors["Email"]</div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label">Phone</label>
        <InputText class="form-control" @bind-Value="Model.Phone" />
        <ValidationMessage For="() => Model.Phone" />
    </div>

    <div class="mb-3">
        <label class="form-label">Insurance Provider</label>
        <InputSelect class="form-select" @bind-Value="Model.InsuranceProvider">
            <option value="">-- Select --</option>
            <option value="Aetna">Aetna</option>
            <option value="BlueCross">BlueCross</option>
            <option value="Cigna">Cigna</option>
            <option value="UnitedHealth">UnitedHealth</option>
            <option value="None">None</option>
        </InputSelect>
        <ValidationMessage For="() => Model.InsuranceProvider" />
    </div>

    @if (!showStep2)
    {
        <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">Next</button>
    }

    @if (showStep2)
    {
        <h3 class="mt-4">Step 2: Appointment Details</h3>

        <div class="mb-3">
            <label class="form-label">Preferred Doctor</label>
            <InputSelect class="form-select" @bind-Value="Model.Doctor" @bind-Value:after="OnDoctorOrDateChanged">
                <option value="">-- Select --</option>
                @foreach (var doc in doctors)
                {
                    <option value="@doc">@doc</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.Doctor" />
            @if (serverErrors.ContainsKey("Doctor"))
            {
                <div class="validation-message">@serverErrors["Doctor"]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Date</label>
            <InputDate class="form-control" @bind-Value="Model.AppointmentDate" @bind-Value:after="OnDoctorOrDateChanged" />
            <ValidationMessage For="() => Model.AppointmentDate" />
        </div>

        <div class="mb-3">
            <label class="form-label">Time Slot</label>
            <InputSelect class="form-select" @bind-Value="Model.TimeSlot">
                <option value="">-- Select --</option>
                @foreach (var slot in timeSlots)
                {
                    <option value="@slot">@slot</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.TimeSlot" />
            @if (serverErrors.ContainsKey("TimeSlot"))
            {
                <div class="validation-message">@serverErrors["TimeSlot"]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Reason for Visit</label>
            <InputTextArea class="form-control" @bind-Value="Model.Reason" />
            <ValidationMessage For="() => Model.Reason" />
        </div>

        <button type="button" class="btn btn-secondary me-2" @onclick="CheckAvailability">Check Availability</button>
        <button type="submit" class="btn btn-primary" disabled="@(!validationPassed)">Book Appointment</button>
    }
</EditForm>

@if (booked)
{
    <div class="alert alert-success mt-3">Appointment booked successfully!</div>
}

@code {
    private AppointmentModel Model { get; set; } = new();
    private bool showStep2;
    private bool booked;
    private bool validationPassed;
    private List<string> doctors = new();
    private List<string> timeSlots = new();
    private Dictionary<string, string> serverErrors = new();

    private EditContext? editContext;

    protected override void OnInitialized()
    {
        editContext = new EditContext(Model);
    }

    private async Task ProceedToStep2()
    {
        editContext = new EditContext(Model);
        var isValid = editContext.Validate();

        // For step 1, only check step-1 fields
        var step1Valid = !string.IsNullOrWhiteSpace(Model.PatientName)
            && !string.IsNullOrWhiteSpace(Model.Email)
            && new System.ComponentModel.DataAnnotations.EmailAddressAttribute().IsValid(Model.Email)
            && !string.IsNullOrWhiteSpace(Model.Phone)
            && !string.IsNullOrWhiteSpace(Model.InsuranceProvider);

        if (step1Valid)
        {
            doctors = await AppointmentService.GetDoctorsAsync();
            showStep2 = true;
        }
    }

    private async Task OnDoctorOrDateChanged()
    {
        serverErrors.Remove("Doctor");
        serverErrors.Remove("TimeSlot");
        validationPassed = false;

        if (!string.IsNullOrWhiteSpace(Model.Doctor) && Model.AppointmentDate != default)
        {
            timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                Model.Doctor, Model.AppointmentDate);
        }
    }

    private async Task CheckAvailability()
    {
        serverErrors.Clear();
        validationPassed = false;

        // Validate step 2 fields client-side first
        if (string.IsNullOrWhiteSpace(Model.Doctor)
            || Model.AppointmentDate == default
            || Model.AppointmentDate <= DateOnly.FromDateTime(DateTime.Today)
            || string.IsNullOrWhiteSpace(Model.TimeSlot)
            || string.IsNullOrWhiteSpace(Model.Reason))
        {
            // Trigger validation display
            editContext = new EditContext(Model);
            editContext.Validate();
            return;
        }

        var errors = await AppointmentService.ValidatePatientAsync(
            Model.Email,
            Model.InsuranceProvider,
            Model.Doctor,
            Model.TimeSlot);

        if (errors.Count > 0)
        {
            serverErrors = errors;
        }
        else
        {
            validationPassed = true;
        }
    }

    private void HandleSubmit()
    {
        if (validationPassed)
        {
            booked = true;
        }
    }

    public class AppointmentModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Patient name is required")]
        public string PatientName { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Email is required")]
        [System.ComponentModel.DataAnnotations.EmailAddress(ErrorMessage = "Invalid email format")]
        public string Email { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Phone is required")]
        public string Phone { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Insurance provider is required")]
        public string InsuranceProvider { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Doctor is required")]
        public string Doctor { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Date is required")]
        [FutureDate(ErrorMessage = "Date must be in the future")]
        public DateOnly AppointmentDate { get; set; }

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Time slot is required")]
        public string TimeSlot { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Reason is required")]
        [System.ComponentModel.DataAnnotations.MaxLength(500, ErrorMessage = "Reason cannot exceed 500 characters")]
        public string Reason { get; set; } = "";
    }

    public class FutureDateAttribute : System.ComponentModel.DataAnnotations.ValidationAttribute
    {
        public override bool IsValid(object? value)
        {
            if (value is DateOnly date)
            {
                return date > DateOnly.FromDateTime(DateTime.Today);
            }
            return false;
        }
    }
}

